def validate_operator(op: str) -> str:
    """Validate and normalize an operator."""
    normalized = ALLOWED_OPERATORS.get(op)
    if normalized is None:
        raise ValueError(f"Invalid operator: '{op}'. Allowed operators: {list(ALLOWED_OPERATORS.keys())}")
    return normalized


def search(
    conditions: List[Dict[str, Any]],
    table: str = "users",
    logic: str = "AND",
    select_fields: Optional[List[str]] = None,
    order_by: Optional[str] = None,
    order_dir: str = "ASC",
    limit: Optional[int] = None,
    offset: Optional[int] = None,
    db_path: str = "database.db"
) -> Tuple[str, list]:
    """
    Build and execute a complex database query from user-specified conditions.

    Args:
        conditions: List of dicts with 'field', 'op', and 'value' keys.
        table: Table name to query (validated against whitelist).
        logic: Logical connector between conditions ('AND' or 'OR').
        select_fields: List of fields to select (None for all).
        order_by: Field to order results by.
        order_dir: 'ASC' or 'DESC'.
        limit: Maximum number of results.
        offset: Number of results to skip.
        db_path: Path to the SQLite database.

    Returns:
        Tuple of (query_string, parameters) for inspection/testing,
        and executes the query against the database.
    """
    # Validate table name against whitelist
    allowed_tables = {"users", "orders", "products", "departments"}
    if table not in allowed_tables:
        raise ValueError(f"Invalid table name: '{table}'. Allowed tables: {allowed_tables}")

    # Validate logic operator
    if logic.upper() not in ("AND", "OR"):
        raise ValueError(f"Invalid logic operator: '{logic}'. Must be 'AND' or 'OR'.")
    logic = logic.upper()

    # Build SELECT clause
    if select_fields:
        validated_select = [validate_field(f) for f in select_fields]
        select_clause = ", ".join(validated_select)
    else:
        select_clause = "*"

    # Build WHERE clause with parameterized queries
    where_parts = []
    params = []

    if not conditions:
        raise ValueError("At least one search condition is required.")

    for i, condition in enumerate(conditions):
        if not isinstance(condition, dict):
            raise ValueError(f"Condition at index {i} must be a dictionary.")

        required_keys = {'field', 'op'}
        if not required_keys.issubset(condition.keys()):
            raise ValueError(f"Condition at index {i} must have 'field' and 'op' keys.")

        field = validate_field(condition['field'])
        operator = validate_operator(condition['op'])

        # Handle operators that don't need a value
        if operator in ('IS NULL', 'IS NOT NULL'):
            where_parts.append(f"{field} {operator}")
            continue

        if 'value' not in condition:
            raise ValueError(f"Condition at index {i} with operator '{operator}' requires a 'value' key.")

        value = condition['value']

        # Handle IN operator with list of values
        if operator == 'IN':
            if not isinstance(value, (list, tuple)):
                raise ValueError(f"IN operator requires a list of values at condition index {i}.")
            if not value:
                raise ValueError(f"IN operator requires a non-empty list at condition index {i}.")
            placeholders = ", ".join(["?"] * len(value))
            where_parts.append(f"{field} IN ({placeholders})")
            params.extend(value)
        else:
            # Standard parameterized condition
            where_parts.append(f"{field} {operator} ?")
            params.append(value)

    where_clause = f" {logic} ".join(where_parts)

    # Build full query
    query = f"SELECT {select_clause} FROM {table} WHERE {where_clause}"

    # Add ORDER BY if specified
    if order_by:
        validated_order = validate_field(order_by)
        if order_dir.upper() not in ("ASC", "DESC"):
            raise ValueError(f"Invalid order direction: '{order_dir}'. Must be 'ASC' or 'DESC'.")
        query += f" ORDER BY {validated_order} {order_dir.upper()}"

    # Add LIMIT and OFFSET
    if limit is not None:
        if not isinstance(limit, int) or limit < 0:
            raise ValueError("Limit must be a non-negative integer.")
        query += " LIMIT ?"
        params.append(limit)

    if offset is not None:
        if not isinstance(offset, int) or offset < 0:
            raise ValueError("Offset must be a non-negative integer.")
        if limit is None:
            query += " LIMIT -1"  # SQLite requires LIMIT before OFFSET
        query += " OFFSET ?"
        params.append(offset)

    return query, params


def execute_search(
    conditions: List[Dict[str, Any]],
    db_path: str = "database.db",
    **kwargs
) -> List[Dict[str, Any]]:
    """
    Execute the search and return results as a list of dictionaries.
    """
    query, params = search(conditions, db_path=db_path, **kwargs)

    conn = sqlite3.connect(db_path)
    conn.row_factory = sqlite3.Row
    cursor = conn.cursor()

    try:
        cursor.execute(query, params)
        rows = cursor.fetchall()
        results = [dict(row) for row in rows]
        return results
    finally:
        cursor.close()
        conn.close()


